(302, 49, 'PLO2', '', 'يجري بحوثاً فقهية، أو بينيّة، تعالج مختلف قضايا المجتمع من المنظور الفقهي.', 2, '2026-02-22 13:48:20', '2026-02-22 13:48:20'),
