(325, 5, 'PLO5', 'To demonstrate proficiency by giving concise, clear and organized written communication about a biological concept.', '', 5, '2026-02-22 14:10:58', '2026-02-22 14:10:58'),
(326, 5, 'PLO6', 'To demonstrate proficiency in oral communication by giving concise, clear and organized oral presentations on a biological topic.', '', 6, '2026-02-22 14:10:58', '2026-02-22 14:10:58'),
